import Link from "next/link";
import type { CaseStudy, CaseStudyMeta, CaseStudySection } from "@/data/case-studies";
import { CaseStudyImage } from "@/components/case-study-image";

type CaseStudyViewProps = {
  study: CaseStudy;
};

function MetaGrid({ meta }: { meta: CaseStudyMeta }) {
  const items = [
    { label: "Role", value: meta.role },
    meta.client && { label: "Client", value: meta.client },
    meta.employer && { label: "Employer", value: meta.employer },
    { label: "Focus areas", value: meta.areas },
  ].filter(Boolean) as { label: string; value: string }[];

  return (
    <div className="grid grid-cols-2 gap-6 sm:grid-cols-4">
      {items.map(({ label, value }) => (
        <div key={label} className="space-y-1">
          <p className="text-xs font-medium uppercase tracking-wider text-zinc-400">
            {label}
          </p>
          <p className="text-sm font-medium text-zinc-200">{value}</p>
        </div>
      ))}
    </div>
  );
}

function SectionBlock({ section }: { section: CaseStudySection }) {
  return (
    <section className="grid gap-8 py-12 sm:grid-cols-2 sm:gap-12 sm:py-16">
      <div className="space-y-2">
        <div className="relative aspect-[4/3] overflow-hidden rounded-xl border border-white/15 bg-zinc-900/60">
          <Image
            src={section.image}
            alt={section.caption || section.title}
            fill
            className="object-cover"
            sizes="(max-width: 640px) 100vw, 50vw"
          />
        </div>
        {section.caption && (
          <p className="text-xs text-zinc-400">{section.caption}</p>
        )}
      </div>
      <div className="flex flex-col justify-center space-y-3">
        <h3
          className="text-lg font-semibold text-zinc-50"
          style={{ fontFamily: "var(--font-crimson)" }}
        >
          {section.title}
        </h3>
        <p className="text-sm leading-relaxed text-zinc-300 whitespace-pre-line">
          {section.body}
        </p>
      </div>
    </section>
  );
}

export function CaseStudyView({ study }: CaseStudyViewProps) {
  const { hero, meta, sections } = study;

  return (
    <article className="min-h-screen bg-[#080808] text-zinc-100">
      <div className="mx-auto max-w-[800px] px-6 pb-24 pt-28 sm:px-10 sm:pt-32">
        {/* Back link */}
        <Link
          href="/#selected-work"
          className="mb-12 inline-flex items-center text-xs font-medium uppercase tracking-wider text-zinc-400 transition hover:text-zinc-200"
        >
          <span className="mr-2">←</span>
          Selected works
        </Link>

        {/* Hero */}
        <header className="space-y-4 pb-12">
          <h1
            className="text-4xl font-semibold text-zinc-50 sm:text-5xl"
            style={{ fontFamily: "var(--font-crimson)" }}
          >
            {hero.title}
          </h1>
          <p className="text-lg text-zinc-300">{hero.subtitle}</p>
          <p className="max-w-2xl text-sm leading-relaxed text-zinc-300/90">
            {hero.description}
          </p>
        </header>

        {/* Meta */}
        <div className="border-t border-white/10 py-8">
          <MetaGrid meta={meta} />
        </div>

        {/* Sections */}
        <div className="divide-y divide-white/10">
          {sections.map((section, i) => (
            <SectionBlock key={i} section={section} />
          ))}
        </div>
      </div>
    </article>
  );
}
